  ('dbb96448-6f0e-4feb-bbb2-9bebf8c67215', '8c885766-f7d2-4dc8-9ffb-d2b575303f32', 'Interpretando os critérios de cálculo da EC 113/21', 'Mais importante do que elaborar o cálculo é interpretar com fidelidade os termos descritos na EC 113/21.', 'https://player-vz-a94806ca-13a.tv.pandavideo.com.br/embed/?v=ef176fbb-d1d7-4a93-a591-8bdb45c370f5', 0, 0, 'aula'),
